/**
 * Validates pagination parameters.
 */
function validatePagination(page, limit) {
  let validatedPage = 1;
  let validatedLimit = DEFAULT_LIMIT;

  if (page !== undefined && page !== null) {
    validatedPage = parseInt(page, 10);
    if (isNaN(validatedPage) || validatedPage < 1) {
      throw new QueryValidationError('Page must be a positive integer');
    }
    if (validatedPage > 10000) {
      throw new QueryValidationError('Page number is too large');
    }
  }

  if (limit !== undefined && limit !== null) {
    validatedLimit = parseInt(limit, 10);
    if (isNaN(validatedLimit) || validatedLimit < 1) {
      throw new QueryValidationError('Limit must be a positive integer');
    }
    if (validatedLimit > MAX_LIMIT) {
      throw new QueryValidationError(
        `Limit cannot exceed ${MAX_LIMIT}`
      );
    }
  }

  return { page: validatedPage, limit: validatedLimit };
}

