/**
 * Builds a safe, validated MongoDB query from user input.
 *
 * @param {Object} filter - The filter criteria (validated against allowlists)
 * @param {Object} projection - The projection specification (validated)
 * @param {Object} sort - The sort criteria (validated)
 * @param {Object} options - Additional options: { page, limit, collection }
 * @returns {Object} - The validated query components ready for MongoDB execution
 */
function queryBuilder(filter, projection, sort, options = {}) {
  // Validate all components
  const validatedFilter = validateFilter(filter);
  const validatedProjection = validateProjection(projection);
  const validatedSort = validateSort(sort);
  const { page, limit } = validatePagination(options.page, options.limit);

  const skip = (page - 1) * limit;

  return {
    filter: validatedFilter,
    projection: validatedProjection,
    sort: validatedSort,
    skip,
    limit,
    page,
  };
}

/**
 * Executes a validated query against a MongoDB collection.
 */
async function executeQuery(db, collectionName, queryParams) {
  // Allowlist of collections that can be queried
  const ALLOWED_COLLECTIONS = new Set(['users', 'orders', 'products', 'logs']);

  if (!ALLOWED_COLLECTIONS.has(collectionName)) {
    throw new QueryValidationError(
      `Collection "${collectionName}" is not queryable`
    );
  }

  const collection = db.collection(collectionName);

  const [results, totalCount] = await Promise.all([
    collection
      .find(queryParams.filter)
      .project(queryParams.projection)
      .sort(queryParams.sort)
      .skip(queryParams.skip)
      .limit(queryParams.limit)
      .maxTimeMS(10000) // 10 second timeout to prevent long-running queries
      .toArray(),
    collection.countDocuments(queryParams.filter, { maxTimeMS: 10000 }),
  ]);

  return {
    data: results,
    pagination: {
      page: queryParams.page,
      limit: queryParams.limit,
      totalCount,
      totalPages: Math.ceil(totalCount / queryParams.limit),
      hasNextPage: queryParams.page * queryParams.limit < totalCount,
      hasPrevPage: queryParams.page > 1,
    },
  };
}

